using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 removed Cosmos DB indexing support.
            // The HasIndex call has been removed — indexes must be managed
            // directly in the Azure portal or via Cosmos DB SDK.

            // Breaking change 2: EF 9 renamed the discriminator property
            // from "Discriminator" to "$type". To keep reading existing
            // documents that use "Discriminator", restore the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 3: EF 9 changed the default id format from
            // "EntityName|KeyValue" to just "KeyValue". To keep reading
            // existing documents with the old "Blog|1" format, opt in to
            // the legacy id format with HasIdProperty + value generation.
            entity.HasPartitionKey(b => b.Id);
        });

        // Alternatively, restore the legacy id format globally:
        // modelBuilder.HasManualThroughput(400); // if needed
    }

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        // Opt-in to preserve the EF 8-style "TypeName|Key" id synthesis
        // so existing documents with id = "Blog|1" can still be found.
        // (No-op if you configure the connection elsewhere; shown for clarity.)
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

